# Additional metrics
# ---------------------------------------------------------------------------

def log_loss(y_true, y_pred, *, eps=1e-15, normalize=True, sample_weight=None,
             labels=None):
    """Cross-entropy / log loss."""
    y_true = np.asarray(y_true)
    y_pred = np.asarray(y_pred, dtype=float)
    y_pred = np.clip(y_pred, eps, 1.0 - eps)
    if y_pred.ndim == 1:
        # Binary case
        losses = -(y_true * np.log(y_pred) + (1 - y_true) * np.log(1 - y_pred))
    else:
        # Multiclass: y_pred is (n_samples, n_classes)
        if labels is None:
            labels = np.arange(y_pred.shape[1])
        label_to_idx = {l: i for i, l in enumerate(labels)}
        n = len(y_true)
        losses = np.zeros(n)
        for i in range(n):
            idx = label_to_idx.get(y_true[i], 0)
            losses[i] = -np.log(y_pred[i, idx])
    if sample_weight is not None:
        losses = losses * np.asarray(sample_weight, dtype=float)
    if normalize:
        return float(np.mean(losses))
    return float(np.sum(losses))


def roc_curve(y_true, y_score, *, pos_label=None, sample_weight=None,
              drop_intermediate=True):
    """Compute ROC curve. Returns (fpr, tpr, thresholds)."""
    y_true = np.asarray(y_true)
    y_score = np.asarray(y_score, dtype=float)
    if pos_label is None:
        pos_label = 1
    y_bin = (y_true == pos_label).astype(int)
    desc_idx = np.argsort(y_score)[::-1]
    y_score_sorted = y_score[desc_idx]
    y_bin_sorted = y_bin[desc_idx]
    if sample_weight is not None:
        sw = np.asarray(sample_weight, dtype=float)[desc_idx]
    else:
        sw = np.ones(len(y_bin_sorted), dtype=float)
    distinct_idx = np.where(np.diff(y_score_sorted))[0]
    threshold_idx = np.concatenate([distinct_idx, [len(y_score_sorted) - 1]])
    tps = np.cumsum(y_bin_sorted * sw)[threshold_idx]
    fps = np.cumsum((1 - y_bin_sorted) * sw)[threshold_idx]
    total_pos = tps[-1]
    total_neg = fps[-1]
    tpr = tps / max(total_pos, 1e-15)
    fpr = fps / max(total_neg, 1e-15)
    thresholds = y_score_sorted[threshold_idx]
    if drop_intermediate:
        optimal = np.concatenate([[True],
                                  np.logical_or(np.diff(fpr), np.diff(tpr)),
                                  [True]])
        fpr = fpr[optimal[1:]]
        tpr = tpr[optimal[1:]]
        thresholds = thresholds[optimal[1:]]
    fpr = np.concatenate([[0.0], fpr])
    tpr = np.concatenate([[0.0], tpr])
    thresholds = np.concatenate([[thresholds[0] + 1], thresholds])
    return fpr, tpr, thresholds


def precision_recall_curve(y_true, probas_pred, *, pos_label=None,
                           sample_weight=None, drop_intermediate=False):
    """Compute precision-recall curve. Returns (precision, recall, thresholds)."""
    y_true = np.asarray(y_true)
    probas_pred = np.asarray(probas_pred, dtype=float)
    if pos_label is None:
        pos_label = 1
    y_bin = (y_true == pos_label).astype(int)
    desc_idx = np.argsort(probas_pred)[::-1]
    probas_sorted = probas_pred[desc_idx]
    y_bin_sorted = y_bin[desc_idx]
    tps = np.cumsum(y_bin_sorted)
    fps = np.cumsum(1 - y_bin_sorted)
    precision_arr = tps / (tps + fps)
    recall_arr = tps / max(tps[-1], 1e-15)
    # Distinct thresholds
    distinct_idx = np.where(np.diff(probas_sorted))[0]
    threshold_idx = np.concatenate([distinct_idx, [len(probas_sorted) - 1]])
    precision_arr = precision_arr[threshold_idx]
    recall_arr = recall_arr[threshold_idx]
    thresholds = probas_sorted[threshold_idx]
    # Add (1.0, 0.0) sentinel
    precision_arr = np.concatenate([precision_arr, [1.0]])
    recall_arr = np.concatenate([recall_arr, [0.0]])
    return precision_arr, recall_arr, thresholds


def average_precision_score(y_true, y_score, *, average='macro', pos_label=1,
                            sample_weight=None):
    """Area under the precision-recall curve."""
    precision_arr, recall_arr, _ = precision_recall_curve(
        y_true, y_score, pos_label=pos_label, sample_weight=sample_weight)
    # Recall is in decreasing order; compute area
    return float(-np.sum(np.diff(recall_arr) * precision_arr[:-1]))


def balanced_accuracy_score(y_true, y_pred, *, sample_weight=None,
                            adjusted=False):
    """Balanced accuracy (macro-averaged recall)."""
    y_true, y_pred = np.asarray(y_true), np.asarray(y_pred)
    classes = np.unique(y_true)
    recalls = []
    for c in classes:
        mask = y_true == c
        if mask.sum() == 0:
            continue
        recalls.append(np.sum(y_pred[mask] == c) / mask.sum())
    ba = float(np.mean(recalls))
    if adjusted:
        n_classes = len(classes)
        chance = 1.0 / n_classes
        ba = (ba - chance) / (1.0 - chance)
    return ba


def cohen_kappa_score(y1, y2, *, labels=None, weights=None,
                      sample_weight=None):
    """Cohen's kappa coefficient."""
    y1, y2 = np.asarray(y1), np.asarray(y2)
    if labels is None:
        labels = np.unique(np.concatenate([y1, y2]))
    n = len(labels)
    cm = confusion_matrix(y1, y2, labels=labels)
    n_samples = cm.sum()
    if n_samples == 0:
        return 0.0
    if weights is None:
        p_o = np.diag(cm).sum() / n_samples
        row_sum = cm.sum(axis=1)
        col_sum = cm.sum(axis=0)
        p_e = np.sum(row_sum * col_sum) / (n_samples ** 2)
    elif weights == 'linear':
        w = np.zeros((n, n))
        for i in range(n):
            for j in range(n):
                w[i, j] = abs(i - j)
        w = w / max(w.max(), 1e-15)
        p_o = 1.0 - np.sum(w * cm) / n_samples
        row_sum = cm.sum(axis=1)
        col_sum = cm.sum(axis=0)
        expected = np.outer(row_sum, col_sum) / n_samples
        p_e = 1.0 - np.sum(w * expected) / n_samples
    elif weights == 'quadratic':
        w = np.zeros((n, n))
        for i in range(n):
            for j in range(n):
                w[i, j] = (i - j) ** 2
        w = w / max(w.max(), 1e-15)
        p_o = 1.0 - np.sum(w * cm) / n_samples
        row_sum = cm.sum(axis=1)
        col_sum = cm.sum(axis=0)
        expected = np.outer(row_sum, col_sum) / n_samples
        p_e = 1.0 - np.sum(w * expected) / n_samples
    else:
        raise ValueError(f"Unknown weights: {weights}")
    if abs(1.0 - p_e) < 1e-15:
        return 0.0
    return float((p_o - p_e) / (1.0 - p_e))


def matthews_corrcoef(y_true, y_pred, *, sample_weight=None):
    """Matthews correlation coefficient."""
    y_true, y_pred = np.asarray(y_true), np.asarray(y_pred)
    cm = confusion_matrix(y_true, y_pred)
    n = cm.shape[0]
    if n == 2:
        tp, fp, fn, tn = cm[1, 1], cm[0, 1], cm[1, 0], cm[0, 0]
        denom = np.sqrt(float((tp + fp) * (tp + fn) * (tn + fp) * (tn + fn)))
        if denom == 0:
            return 0.0
        return float((tp * tn - fp * fn) / denom)
    # Multiclass MCC
    t_sum = cm.sum(axis=1)
    p_sum = cm.sum(axis=0)
    c = np.trace(cm)
    s = cm.sum()
    s2 = s * s
    cov_ytyp = c * s - np.dot(t_sum, p_sum)
    cov_ypyp = s2 - np.dot(p_sum, p_sum)
    cov_ytyt = s2 - np.dot(t_sum, t_sum)
    denom = np.sqrt(float(cov_ypyp) * float(cov_ytyt))
    if denom == 0:
        return 0.0
    return float(cov_ytyp / denom)


def hamming_loss(y_true, y_pred, *, sample_weight=None):
    """Fraction of labels that are incorrectly predicted."""
    y_true, y_pred = np.asarray(y_true), np.asarray(y_pred)
    if sample_weight is not None:
        sw = np.asarray(sample_weight, dtype=float)
        return float(np.average(y_true != y_pred, weights=sw))
    return float(np.mean(y_true != y_pred))


def jaccard_score(y_true, y_pred, *, labels=None, pos_label=1,
                  average='binary', sample_weight=None, zero_division='warn'):
    """Jaccard similarity coefficient."""
    y_true, y_pred = np.asarray(y_true), np.asarray(y_pred)
    if average == 'binary':
        tp = np.sum((y_true == pos_label) & (y_pred == pos_label))
        fp = np.sum((y_true != pos_label) & (y_pred == pos_label))
        fn = np.sum((y_true == pos_label) & (y_pred != pos_label))
        denom = tp + fp + fn
        if denom == 0:
            return 0.0 if zero_division == 0 else 0.0
        return float(tp / denom)
    if labels is None:
        labels = np.unique(np.concatenate([y_true, y_pred]))
    scores = []
    supports = []
    for label in labels:
        tp = np.sum((y_true == label) & (y_pred == label))
        fp = np.sum((y_true != label) & (y_pred == label))
        fn = np.sum((y_true == label) & (y_pred != label))
        denom = tp + fp + fn
        scores.append(float(tp / denom) if denom > 0 else 0.0)
        supports.append(np.sum(y_true == label))
    if average == 'macro':
        return float(np.mean(scores))
    elif average == 'weighted':
        return float(np.average(scores, weights=supports))
    elif average == 'micro':
        tp_total = sum(np.sum((y_true == l) & (y_pred == l)) for l in labels)
        fp_total = sum(np.sum((y_true != l) & (y_pred == l)) for l in labels)
        fn_total = sum(np.sum((y_true == l) & (y_pred != l)) for l in labels)
        d = tp_total + fp_total + fn_total
        return float(tp_total / d) if d > 0 else 0.0
    return np.array(scores)


def explained_variance_score(y_true, y_pred, *, sample_weight=None,
                             multioutput='uniform_average'):
    """Explained variance regression score."""
    y_true = np.asarray(y_true, dtype=float)
    y_pred = np.asarray(y_pred, dtype=float)
    diff = y_true - y_pred
    if sample_weight is not None:
        sw = np.asarray(sample_weight, dtype=float)
        numerator = np.average((diff - np.average(diff, weights=sw)) ** 2, weights=sw)
        denominator = np.average((y_true - np.average(y_true, weights=sw)) ** 2, weights=sw)
    else:
        numerator = np.var(diff)
        denominator = np.var(y_true)
    if denominator == 0:
        return 0.0 if numerator != 0 else 1.0
    return float(1.0 - numerator / denominator)


def max_error(y_true, y_pred):
    """Maximum residual error."""
    y_true = np.asarray(y_true, dtype=float)
    y_pred = np.asarray(y_pred, dtype=float)
    return float(np.max(np.abs(y_true - y_pred)))


def median_absolute_error(y_true, y_pred, *, multioutput='uniform_average',
                          sample_weight=None):
    """Median absolute error."""
    y_true = np.asarray(y_true, dtype=float)
    y_pred = np.asarray(y_pred, dtype=float)
    return float(np.median(np.abs(y_true - y_pred)))


def mean_absolute_percentage_error(y_true, y_pred, *, sample_weight=None,
                                   multioutput='uniform_average'):
    """Mean absolute percentage error."""
    y_true = np.asarray(y_true, dtype=float)
    y_pred = np.asarray(y_pred, dtype=float)
    eps = np.finfo(float).eps
    mape = np.abs((y_true - y_pred) / np.maximum(np.abs(y_true), eps))
    if sample_weight is not None:
        return float(np.average(mape, weights=np.asarray(sample_weight, dtype=float)))
    return float(np.mean(mape))


def pairwise_distances(X, Y=None, metric='euclidean', *, n_jobs=None,
                       force_all_finite=True, **kwds):
    """Compute pairwise distance matrix."""
    X = np.asarray(X, dtype=float)
    if Y is None:
        Y = X
    else:
        Y = np.asarray(Y, dtype=float)
    if metric == 'euclidean':
        # Efficient computation: ||x-y||^2 = ||x||^2 + ||y||^2 - 2*x.y
        XX = np.sum(X ** 2, axis=1)[:, np.newaxis]
        YY = np.sum(Y ** 2, axis=1)[np.newaxis, :]
        D = XX + YY - 2.0 * X.dot(Y.T)
        np.maximum(D, 0.0, out=D)
        return np.sqrt(D)
    elif metric == 'manhattan' or metric == 'cityblock':
        n, m = X.shape[0], Y.shape[0]
        D = np.zeros((n, m))
        for i in range(n):
            D[i] = np.sum(np.abs(X[i] - Y), axis=1)
        return D
    elif metric == 'cosine':
        X_norm = X / np.maximum(np.linalg.norm(X, axis=1, keepdims=True), 1e-15)
        Y_norm = Y / np.maximum(np.linalg.norm(Y, axis=1, keepdims=True), 1e-15)
        return 1.0 - X_norm.dot(Y_norm.T)
    elif metric == 'chebyshev':
        n, m = X.shape[0], Y.shape[0]
        D = np.zeros((n, m))
        for i in range(n):
            D[i] = np.max(np.abs(X[i] - Y), axis=1)
        return D
    elif callable(metric):
        n, m = X.shape[0], Y.shape[0]
        D = np.zeros((n, m))
        for i in range(n):
            for j in range(m):
                D[i, j] = metric(X[i], Y[j], **kwds)
        return D
    else:
        raise ValueError(f"Unknown metric: {metric}")


def _contingency_matrix(labels_true, labels_pred):
    """Build contingency matrix for clustering metrics."""
    labels_true = np.asarray(labels_true)
    labels_pred = np.asarray(labels_pred)
    classes_true = np.unique(labels_true)
    classes_pred = np.unique(labels_pred)
    n_true = len(classes_true)
    n_pred = len(classes_pred)
    map_true = {c: i for i, c in enumerate(classes_true)}
    map_pred = {c: i for i, c in enumerate(classes_pred)}
    contingency = np.zeros((n_true, n_pred), dtype=int)
    for t, p in zip(labels_true, labels_pred):
        contingency[map_true[t], map_pred[p]] += 1
    return contingency, classes_true, classes_pred


def adjusted_rand_score(labels_true, labels_pred):
    """Adjusted Rand Index for clustering."""
    contingency, _, _ = _contingency_matrix(labels_true, labels_pred)
    n = contingency.sum()
    if n < 2:
        return 0.0
    # Sum of C(n_ij, 2) for all cells
    sum_comb_c = sum(int(nij) * (int(nij) - 1) // 2
                     for nij in contingency.flatten())
    # Row sums and column sums
    row_sums = contingency.sum(axis=1)
    col_sums = contingency.sum(axis=0)
    sum_comb_a = sum(int(a) * (int(a) - 1) // 2 for a in row_sums)
    sum_comb_b = sum(int(b) * (int(b) - 1) // 2 for b in col_sums)
    total_comb = n * (n - 1) // 2
    expected = sum_comb_a * sum_comb_b / max(total_comb, 1)
    max_index = 0.5 * (sum_comb_a + sum_comb_b)
    denom = max_index - expected
    if abs(denom) < 1e-15:
        return 0.0
    return float((sum_comb_c - expected) / denom)


def _entropy(labels):
    """Compute entropy of label array."""
    labels = np.asarray(labels)
    _, counts = np.unique(labels, return_counts=True)
    probs = counts / counts.sum()
    probs = probs[probs > 0]
    return -np.sum(probs * np.log(probs))


def _mutual_info(labels_true, labels_pred):
    """Compute mutual information between two label arrays."""
    contingency, _, _ = _contingency_matrix(labels_true, labels_pred)
    n = contingency.sum()
    if n == 0:
        return 0.0
    row_sums = contingency.sum(axis=1)
    col_sums = contingency.sum(axis=0)
    mi = 0.0
    for i in range(contingency.shape[0]):
        for j in range(contingency.shape[1]):
            if contingency[i, j] > 0:
                mi += (contingency[i, j] / n) * np.log(
                    n * contingency[i, j] / (row_sums[i] * col_sums[j]))
    return mi


def normalized_mutual_info_score(labels_true, labels_pred, *,
                                 average_method='arithmetic'):
    """Normalized Mutual Information between two clusterings."""
    mi = _mutual_info(labels_true, labels_pred)
    h_true = _entropy(labels_true)
    h_pred = _entropy(labels_pred)
    if average_method == 'arithmetic':
        normalizer = 0.5 * (h_true + h_pred)
    elif average_method == 'geometric':
        normalizer = np.sqrt(h_true * h_pred)
    elif average_method == 'min':
        normalizer = min(h_true, h_pred)
    elif average_method == 'max':
        normalizer = max(h_true, h_pred)
    else:
        normalizer = 0.5 * (h_true + h_pred)
    if normalizer < 1e-15:
        return 0.0
    return float(mi / normalizer)


def homogeneity_score(labels_true, labels_pred):
    """Homogeneity metric of a cluster labeling."""
    h_true = _entropy(labels_true)
    if h_true < 1e-15:
        return 1.0
    # H(C|K) = H(C,K) - H(K)
    contingency, _, _ = _contingency_matrix(labels_true, labels_pred)
    n = contingency.sum()
    h_ck = 0.0
    col_sums = contingency.sum(axis=0)
    for j in range(contingency.shape[1]):
        for i in range(contingency.shape[0]):
            if contingency[i, j] > 0 and col_sums[j] > 0:
                h_ck -= (contingency[i, j] / n) * np.log(
                    contingency[i, j] / col_sums[j])
    return float(1.0 - h_ck / h_true)


def completeness_score(labels_true, labels_pred):
    """Completeness metric of a cluster labeling."""
    h_pred = _entropy(labels_pred)
    if h_pred < 1e-15:
        return 1.0
    # H(K|C) = H(K,C) - H(C)
    contingency, _, _ = _contingency_matrix(labels_true, labels_pred)
    n = contingency.sum()
    h_kc = 0.0
    row_sums = contingency.sum(axis=1)
    for i in range(contingency.shape[0]):
        for j in range(contingency.shape[1]):
            if contingency[i, j] > 0 and row_sums[i] > 0:
                h_kc -= (contingency[i, j] / n) * np.log(
                    contingency[i, j] / row_sums[i])
    return float(1.0 - h_kc / h_pred)


def v_measure_score(labels_true, labels_pred, *, beta=1.0):
    """V-measure: harmonic mean of homogeneity and completeness."""
    h = homogeneity_score(labels_true, labels_pred)
    c = completeness_score(labels_true, labels_pred)
    if h + c == 0:
        return 0.0
    return float((1 + beta) * h * c / (beta * h + c))


def calinski_harabasz_score(X, labels):
    """Calinski-Harabasz Index (ratio of between/within cluster dispersion)."""
    X = np.asarray(X, dtype=float)
    labels = np.asarray(labels)
    n_samples, n_features = X.shape
    unique_labels = np.unique(labels)
    n_labels = len(unique_labels)
    if n_labels < 2:
        return 0.0
    overall_mean = np.mean(X, axis=0)
    bgss = 0.0  # between-group sum of squares
    wgss = 0.0  # within-group sum of squares
    for k in unique_labels:
        cluster_k = X[labels == k]
        n_k = len(cluster_k)
        mean_k = np.mean(cluster_k, axis=0)
        bgss += n_k * np.sum((mean_k - overall_mean) ** 2)
        wgss += np.sum((cluster_k - mean_k) ** 2)
    if wgss == 0:
        return 0.0
    return float(bgss / wgss * (n_samples - n_labels) / (n_labels - 1))


def davies_bouldin_score(X, labels):
    """Davies-Bouldin Index."""
    X = np.asarray(X, dtype=float)
    labels = np.asarray(labels)
    unique_labels = np.unique(labels)
    n_clusters = len(unique_labels)
    if n_clusters < 2:
        return 0.0
    centroids = np.zeros((n_clusters, X.shape[1]))
    s = np.zeros(n_clusters)  # average distance to centroid
    for idx, k in enumerate(unique_labels):
        members = X[labels == k]
        centroids[idx] = np.mean(members, axis=0)
        s[idx] = np.mean(np.sqrt(np.sum((members - centroids[idx]) ** 2, axis=1)))
    db = 0.0
    for i in range(n_clusters):
        max_ratio = 0.0
        for j in range(n_clusters):
            if i == j:
                continue
            d_ij = np.sqrt(np.sum((centroids[i] - centroids[j]) ** 2))
            if d_ij < 1e-15:
                ratio = 0.0
            else:
                ratio = (s[i] + s[j]) / d_ij
            if ratio > max_ratio:
                max_ratio = ratio
        db += max_ratio
    return float(db / n_clusters)


def mean_pinball_loss(y_true, y_pred, *, sample_weight=None, alpha=0.5,
                      multioutput='uniform_average'):
    """Pinball loss (quantile loss)."""
    y_true = np.asarray(y_true, dtype=float)
    y_pred = np.asarray(y_pred, dtype=float)
    diff = y_true - y_pred
    loss = np.where(diff >= 0, alpha * diff, (alpha - 1.0) * diff)
    if sample_weight is not None:
        return float(np.average(loss, weights=np.asarray(sample_weight, dtype=float)))
    return float(np.mean(loss))


def d2_pinball_score(y_true, y_pred, *, sample_weight=None, alpha=0.5,
                     multioutput='uniform_average'):
    """D^2 score using pinball loss (1 - loss/null_loss)."""
    y_true = np.asarray(y_true, dtype=float)
    y_pred = np.asarray(y_pred, dtype=float)
    loss = mean_pinball_loss(y_true, y_pred, sample_weight=sample_weight,
                            alpha=alpha)
    # Null model: predict the alpha-quantile of y_true
    q = np.percentile(y_true, alpha * 100)
    null_pred = np.full_like(y_true, q)
    null_loss = mean_pinball_loss(y_true, null_pred, sample_weight=sample_weight,
                                 alpha=alpha)
    if null_loss < 1e-15:
        return 0.0
    return float(1.0 - loss / null_loss)


def top_k_accuracy_score(y_true, y_score, *, k=2, normalize=True,
                         sample_weight=None, labels=None):
    """Top-k accuracy classification score."""
    y_true = np.asarray(y_true)
    y_score = np.asarray(y_score, dtype=float)
    if labels is None:
        labels = np.arange(y_score.shape[1])
    n = len(y_true)
    # For each sample, find top-k predicted labels
    top_k_indices = np.argsort(y_score, axis=1)[:, -k:]
    top_k_labels = np.array([[labels[j] for j in row] for row in top_k_indices])
    hits = np.array([y_true[i] in top_k_labels[i] for i in range(n)])
    if sample_weight is not None:
        sw = np.asarray(sample_weight, dtype=float)
        if normalize:
            return float(np.average(hits, weights=sw))
        return float(np.sum(hits * sw))
    if normalize:
        return float(np.mean(hits))
    return int(np.sum(hits))


def zero_one_loss(y_true, y_pred, *, normalize=True, sample_weight=None):
    """Zero-one classification loss (fraction or count of misclassifications)."""
    y_true, y_pred = np.asarray(y_true), np.asarray(y_pred)
    incorrect = (y_true != y_pred)
    if sample_weight is not None:
        sw = np.asarray(sample_weight, dtype=float)
        if normalize:
            return float(np.average(incorrect, weights=sw))
        return float(np.sum(incorrect * sw))
    if normalize:
        return float(np.mean(incorrect))
    return int(np.sum(incorrect))


def brier_score_loss(y_true, y_prob, *, sample_weight=None, pos_label=None):
    """Brier score loss (mean squared error of predicted probabilities)."""
    y_true = np.asarray(y_true)
    y_prob = np.asarray(y_prob, dtype=float)
    if pos_label is not None:
        y_true = (y_true == pos_label).astype(float)
    else:
        y_true = y_true.astype(float)
    if sample_weight is not None:
        return float(np.average((y_true - y_prob) ** 2,
                                weights=np.asarray(sample_weight, dtype=float)))
    return float(np.mean((y_true - y_prob) ** 2))
